```class Solution {
    public int findMaxK(int[] nums) {
        Set<Integer> set = new HashSet<>();
        for (int num : nums) {
            set.add(num);
        }
        int maxK = -1;
        for (int num : set) {
            if (set.contains(-num)) {
                maxK = Math.max(maxK, Math.abs(num));
            }
        }
        return maxK;
    }
}```
